const BASE_CLASS = 'scroll-reveal-item';
const VISIBLE_CLASS = 'scroll-reveal-visible';
const GROUP_ATTRIBUTE = 'data-scroll-group';
const TARGET_ATTRIBUTE = 'data-scroll-reveal';
const IGNORE_ATTRIBUTE = 'data-scroll-ignore';
const MAX_STAGGER_DELAY = 35;

const defaultOptions = {
  threshold: 0,
  rootMargin: '0px 0px 8% 0px',
  once: true
};

/**
 * Collect targets defined with data-scroll-group (children) and data-scroll-reveal (element itself)
 * @param {HTMLElement} root
 * @returns {HTMLElement[]}
 */
function collectTargets(root) {
  const targets = [];
  const seen = new Set();

  const manualTargets = root.querySelectorAll(`[${TARGET_ATTRIBUTE}]`);
  manualTargets.forEach((el) => {
    if (seen.has(el)) {
      return;
    }
    seen.add(el);
    targets.push(el);
  });

  const groupContainers = root.querySelectorAll(`[${GROUP_ATTRIBUTE}]`);
  groupContainers.forEach((container) => {
    const requestedStep = Number(container.dataset.scrollStep || MAX_STAGGER_DELAY);
    const step = Math.min(requestedStep, MAX_STAGGER_DELAY);
    const includeSelf = container.dataset.scrollGroup === 'self' || container.classList.contains('scroll-container');
    const elements = [];

    if (includeSelf) {
      elements.push(container);
    }

    Array.from(container.children || []).forEach((child) => {
      if (
        !child ||
        child.nodeType !== 1 ||
        child.hasAttribute(IGNORE_ATTRIBUTE) ||
        child.tagName === 'SCRIPT' ||
        child.tagName === 'STYLE' ||
        child.tagName === 'BR'
      ) {
        return;
      }
      elements.push(child);
    });

    elements.forEach((el, index) => {
      if (seen.has(el)) {
        return;
      }
      seen.add(el);
      el.style.setProperty('--scroll-delay', `${index * step}ms`);
      targets.push(el);
    });
  });

  const scrollGalleries = root.querySelectorAll('.scroll-container');
  scrollGalleries.forEach((el) => {
    if (seen.has(el)) {
      return;
    }
    seen.add(el);
    targets.push(el);
  });

  return targets;
}

function isElementVisible(el, threshold = 0) {
  if (!el || typeof window === 'undefined') {
    return false;
  }
  const rect = el.getBoundingClientRect();
  const viewHeight = window.innerHeight || document.documentElement.clientHeight || 0;
  const viewWidth = window.innerWidth || document.documentElement.clientWidth || 0;

  if (viewHeight === 0 || viewWidth === 0) {
    return false;
  }

  const elementHeight = rect.height || 1;
  const visibleHeight = Math.max(0, Math.min(rect.bottom, viewHeight) - Math.max(rect.top, 0));
  if (visibleHeight === 0) {
    return false;
  }
  if (threshold <= 0) {
    return true;
  }
  const ratio = visibleHeight / elementHeight;
  return ratio >= threshold;
}

export function initScrollAnimations(root, options = {}) {
  if (!root) {
    return () => {};
  }

  const settings = {
    ...defaultOptions,
    ...options
  };

  const targets = collectTargets(root);

  if (!targets.length) {
    return () => {};
  }

  const supportsObserver = typeof window !== 'undefined' && 'IntersectionObserver' in window;

  targets.forEach((target) => {
    target.classList.add(BASE_CLASS);
  });

  if (!supportsObserver) {
    targets.forEach((target) => {
      target.classList.add(VISIBLE_CLASS);
    });
    return () => {
      targets.forEach((target) => {
        target.classList.remove(BASE_CLASS, VISIBLE_CLASS);
        target.style.removeProperty('--scroll-delay');
      });
    };
  }

  const observer = new IntersectionObserver((entries) => {
    entries.forEach((entry) => {
      if (entry.isIntersecting) {
        entry.target.classList.add(VISIBLE_CLASS);
        if (settings.once) {
          observer.unobserve(entry.target);
        }
      } else if (!settings.once) {
        entry.target.classList.remove(VISIBLE_CLASS);
      }
    });
  }, settings);

  targets.forEach((target) => {
    observer.observe(target);
  });

  const hasWindow = typeof window !== 'undefined';
  let rafId = null;
  let timeoutId = null;
  let loadHandler = null;

  const revealVisibleTargets = () => {
    targets.forEach((target) => {
      if (target.classList.contains(VISIBLE_CLASS)) {
        return;
      }
      if (isElementVisible(target, settings.threshold)) {
        target.classList.add(VISIBLE_CLASS);
        if (settings.once) {
          observer.unobserve(target);
        }
      }
    });
  };

  if (hasWindow) {
    const raf = window.requestAnimationFrame || ((cb) => window.setTimeout(cb, 16));
    rafId = raf(() => {
      revealVisibleTargets();
      rafId = null;
    });
    timeoutId = window.setTimeout(() => {
      revealVisibleTargets();
    }, 400);
    loadHandler = () => {
      revealVisibleTargets();
    };
    window.addEventListener('load', loadHandler, { once: true });
  }

  return () => {
    observer.disconnect();
    if (hasWindow) {
      if (rafId !== null) {
        if (window.cancelAnimationFrame) {
          window.cancelAnimationFrame(rafId);
        } else {
          window.clearTimeout(rafId);
        }
      }
      if (timeoutId) {
        window.clearTimeout(timeoutId);
      }
      if (loadHandler) {
        window.removeEventListener('load', loadHandler);
      }
    }
    targets.forEach((target) => {
      target.classList.remove(BASE_CLASS, VISIBLE_CLASS);
      target.style.removeProperty('--scroll-delay');
    });
  };
}
